#!/usr/bin/env python3
"""cut_line.py — run on freeze day to finalise train scope."""
import os, sys
import requests

REPO   = os.environ["GITHUB_REPOSITORY"]          # org/repo
TOKEN  = os.environ["GH_TOKEN"]
TRAIN  = os.environ["TRAIN_NUMBER"]                # e.g. "42"
SLACK  = os.environ["SLACK_RELEASE_WEBHOOK"]

API = "https://api.github.com"
H   = {"Authorization": f"Bearer {TOKEN}", "Accept": "application/vnd.github+json"}

def get_milestone_id(title: str) -> int:
    ms = requests.get(f"{API}/repos/{REPO}/milestones", headers=H).json()
    for m in ms:
        if m["title"] == title:
            return m["number"]
    raise SystemExit(f"Milestone '{title}' not found")

def label_prs(milestone_id: int) -> tuple[list, list]:
    in_train, missed = [], []
    page = 1
    while True:
        prs = requests.get(
            f"{API}/repos/{REPO}/pulls",
            headers=H,
            params={"state": "open", "per_page": 100, "page": page}
        ).json()
        if not prs:
            break
        for pr in prs:
            ms = pr.get("milestone")
            label = "in-train" if (ms and ms["number"] == milestone_id) else "missed-train"
            requests.post(
                f"{API}/repos/{REPO}/issues/{pr['number']}/labels",
                headers=H,
                json={"labels": [label]}
            )
            (in_train if label == "in-train" else missed).append(pr["number"])
        page += 1
    return in_train, missed

def post_slack(in_train: list, missed: list) -> None:
    msg = (
        f":scissors: *Train {TRAIN} cut-line complete*\n"
        f"  :white_check_mark: In-train PRs: {len(in_train)} — {', '.join(f'#{n}' for n in in_train[:10])}\n"
        f"  :no_entry: Missed-train PRs: {len(missed)} — these ship on Train {int(TRAIN)+1}"
    )
    requests.post(SLACK, json={"text": msg})

if __name__ == "__main__":
    mid = get_milestone_id(f"Train {TRAIN}")
    in_t, missed = label_prs(mid)
    post_slack(in_t, missed)
    print(f"Train {TRAIN}: {len(in_t)} in, {len(missed)} missed")
